    partition_valid_ = false;
    checksum_valid_ = false;

    // Find the assets partition
    esp_partition_t* partition = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, 
                                                         ESP_PARTITION_SUBTYPE_ANY, 
                                                         "assets");
    if (partition == nullptr) {
