bool GetAssetData(const std::string &name, void *&ptr, size_t &size) {
    // Get instance of AssetManager singleton
    auto &assets_manager = AssetManager::Instance();

    // Look up the asset by name in the assets map
    auto it = assets_manager.assets_.find(name);
    if (it == assets_manager.assets_.end()) {
        ESP_LOGE("Assets", "Asset not found: %s", name.c_str());
        return false;
    }

    const auto &asset = it->second;

    // Check if mmap_root_ is valid
    if (assets_manager.mmap_root_ == nullptr) {
        ESP_LOGE("Assets", "Memory mapping not initialized");
        return false;
    }

    // Calculate the pointer address using mmap_root_ + asset.offset
    uint8_t *data_ptr = static_cast<uint8_t*>(assets_manager.mmap_root_) + asset.offset;

    // Validate the magic bytes at the beginning of the asset data ('ZZ')
    if (asset.size < 2 || data_ptr[0] != 'Z' || data_ptr[1] != 'Z') {
        ESP_LOGE("Assets", "Invalid magic bytes for asset: %s", name.c_str());
        return false;
    }

    // Adjust the pointer to skip the magic bytes before returning
    ptr = data_ptr + 2;

    // Set the size to exclude the magic bytes
    size = asset.size - 2;

    return true;
}

const char* DeviceStateMachine::GetStateName(DeviceState state) {
    // Get the number of valid states (excluding the "invalid_state" fallback)
    static const size_t kValidStateCount = sizeof(STATE_STRINGS) / sizeof(STATE_STRINGS[0]) - 1;

    // Check if the state is within valid bounds
    if (static_cast<size_t>(state) < kValidStateCount) {
        return STATE_STRINGS[static_cast<size_t>(state)];
    }

    // Return the invalid state string for out-of-bounds values
    return STATE_STRINGS[kValidStateCount];
}

bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const {
    // Log the transition attempt for debugging
    LOG(DEBUG) << "Checking transition from " << GetStateName(from) 
               << " to " << GetStateName(to);

    // Allow same state transitions (no-op)
    if (from == to) {
        return true;
    }

    // Define valid transitions based on state enum values
    switch (from) {
        case kDeviceStateUninitialized:
            // From uninitialized, can only go to initializing or fatal error
            return (to == kDeviceStateInitializing || 
                    to == kDeviceStateFatalError);

        case kDeviceStateInitializing:
            // From initializing, can go to activating or fatal error
            return (to == kDeviceStateActivating || 
                    to == kDeviceStateFatalError);

        case kDeviceStateActivating:
            // From activating, typically goes to idle or error states
            return (to == kDeviceStateIdle || 
                    to == kDeviceStateFatalError ||
                    to == kDeviceStateError);

        case kDeviceStateIdle:
            // From idle, can transition to most active states
            return (to == kDeviceStateListening || 
                    to == kDeviceStateSpeaking || 
                    to == kDeviceStateUpdating ||
                    to == kDeviceStateError ||
                    to == kDeviceStateFatalError);

        case kDeviceStateListening:
            // From listening, can go to processing or back to idle
            return (to == kDeviceStateProcessing || 
                    to == kDeviceStateIdle ||
                    to == kDeviceStateError ||
                    to == kDeviceStateFatalError);

        case kDeviceStateProcessing:
            // From processing, typically goes to speaking or idle
            return (to == kDeviceStateSpeaking || 
                    to == kDeviceStateIdle ||
                    to == kDeviceStateError ||
                    to == kDeviceStateFatalError);

        case kDeviceStateSpeaking:
            // From speaking, usually returns to idle
            return (to == kDeviceStateIdle || 
                    to == kDeviceStateError ||
                    to == kDeviceStateFatalError);

        case kDeviceStateUpdating:
            // From updating, goes back to idle when complete
            return (to == kDeviceStateIdle || 
                    to == kDeviceStateError ||
                    to == kDeviceStateFatalError);

        case kDeviceStateError:
            // From error state, can reset to idle or go to fatal
            return (to == kDeviceStateIdle || 
                    to == kDeviceStateFatalError);

        case kDeviceStateFatalError:
            // Fatal error is terminal state, no valid transitions out
            return false;

        default:
            // Unknown state transitions are not allowed
            LOG(WARNING) << "Invalid transition attempted from unknown state: " 
                         << static_cast<int>(from);
            return false;
    }

    // Default deny for any unhandled cases
    return false;
}

bool DeviceStateMachine::TransitionTo(DeviceState new_state) {
    // Load the current state atomically
    DeviceState old_state = current_state_.load();

    // Check if the transition is valid
    if (!IsValidTransition(old_state, new_state)) {
        ESP_LOGW("DeviceStateMachine", "Invalid state transition requested: %d -> %d", 
                 static_cast<int>(old_state), static_cast<int>(new_state));
        return false;
    }

    // Update the state atomically
    current_state_.store(new_state);

    // Log the successful transition
    ESP_LOGI("DeviceStateMachine", "State transition: %d -> %d", 
             static_cast<int>(old_state), static_cast<int>(new_state));

    // Notify all registered listeners about the state change
    NotifyStateChange(old_state, new_state);

    return true;
}

int DeviceStateMachine::AddStateChangeListener(StateCallback callback) {
    std::lock_guard<std::mutex> lock(mutex_);

    int listener_id = next_listener_id_++;
    listeners_.emplace_back(listener_id, std::move(callback));

    return listener_id;
}

void DeviceStateMachine::RemoveStateChangeListener(int listener_id) {
    std::lock_guard<std::mutex> lock(mutex_);
    listeners_.erase(
        std::remove_if(listeners_.begin(), listeners_.end(),
                      [listener_id](const auto& listener) {
                          return listener.first == listener_id;
                      }),
        listeners_.end());
}

void NotifyStateChange(DeviceState old_state, DeviceState new_state) {
    ESP_LOGI("Device", "State changed from %d to %d", static_cast<int>(old_state), static_cast<int>(new_state));

    std::lock_guard<std::mutex> lock(mutex_);
    for (auto& listener : listeners_) {
        if (listener) {
            listener(old_state, new_state);
        }
    }
}

