esp_err_t OtaVersionManager::CheckVersion() {
    std::string url = GetCheckVersionUrl();
    if (url.empty()) {
        ESP_LOGE(TAG, "Failed to construct version check URL");
        return ESP_ERR_INVALID_STATE;
    }

    esp_http_client_config_t config = {};
    config.url = url.c_str();
    config.transport_type = HTTP_TRANSPORT_UNKNOWN;

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return ESP_FAIL;
    }

    SetupHttp(client);

    esp_err_t err = esp_http_client_perform(client);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "HTTP GET request failed: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return err;
    }

    int status_code = esp_http_client_get_status_code(client);
    if (status_code != 200) {
        ESP_LOGE(TAG, "Received non-200 status code: %d", status_code);
        esp_http_client_cleanup(client);
        return ESP_FAIL;
    }

    // Read response data
    char *buffer = (char *)malloc(1024);
    if (!buffer) {
        ESP_LOGE(TAG, "Memory allocation failed");
        esp_http_client_cleanup(client);
        return ESP_ERR_NO_MEM;
    }

    int read_len = esp_http_client_read(client, buffer, 1024);
    if (read_len <= 0) {
        ESP_LOGE(TAG, "Failed to read HTTP response");
        free(buffer);
        esp_http_client_cleanup(client);
        return ESP_FAIL;
    }
    buffer[read_len] = '\0';

    ESP_LOGD(TAG, "Server Response: %s", buffer);

    cJSON *json = cJSON_Parse(buffer);
    if (!json) {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        free(buffer);
        esp_http_client_cleanup(client);
        return ESP_FAIL;
    }

    cJSON *current_ver_item = cJSON_GetObjectItem(json, "current_version");
    cJSON *firmware_url_item = cJSON_GetObjectItem(json, "firmware_url");

    if (!cJSON_IsString(current_ver_item) || !cJSON_IsString(firmware_url_item)) {
        ESP_LOGE(TAG, "Invalid version info in JSON response");
        cJSON_Delete(json);
        free(buffer);
        esp_http_client_cleanup(client);
        return ESP_FAIL;
    }

    std::string remote_version = current_ver_item->valuestring;
    firmware_url_ = firmware_url_item->valuestring;

    std::string local_version = ParseVersion(CONFIG_FIRMWARE_VERSION); // Assuming macro defines local version
    bool new_available = IsNewVersionAvailable(remote_version, local_version);

    has_new_version_ = new_available;

    cJSON_Delete(json);
    free(buffer);
    esp_http_client_cleanup(client);

    MarkCurrentVersionValid();

    ESP_LOGI(TAG, "Version check completed. New version available: %s", new_available ? "YES" : "NO");

    return ESP_OK;
}

