static const char *TAG = "OTA";

bool OtaUpgradeManager::Upgrade(const std::string &firmware_url,
                                std::function<void(int progress, size_t speed)> progress_callback) {
    esp_err_t err;
    esp_ota_handle_t ota_handle = 0;
    const esp_partition_t *update_partition = nullptr;

    // Step 1: Validate update partition
    update_partition = esp_ota_get_next_update_partition(nullptr);
    if (!update_partition) {
        ESP_LOGE(TAG, "Failed to find next update partition");
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition subtype %d at offset 0x%x",
             update_partition->subtype, update_partition->address);

    // Step 2: Begin OTA update
    err = esp_ota_begin(update_partition, OTA_WITH_SEQUENTIAL_WRITES, &ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed (%s)", esp_err_to_name(err));
        return false;
    }

    // Step 3: Download and write firmware
    esp_http_client_config_t config = {};
    config.url = firmware_url.c_str();
    config.cert_pem = nullptr; // Optional CA cert verification

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        esp_ota_abort(ota_handle);
        return false;
    }

    err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        esp_ota_abort(ota_handle);
        return false;
    }

    int content_length = esp_http_client_fetch_headers(client);
    if (content_length <= 0) {
        ESP_LOGW(TAG, "Invalid content length: %d", content_length);
    }

    const int buffer_size = 512;
    uint8_t *buffer = (uint8_t *)malloc(buffer_size);
    if (!buffer) {
        ESP_LOGE(TAG, "Failed to allocate buffer");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        esp_ota_abort(ota_handle);
        return false;
    }

    int total_read = 0;
    int64_t last_report_time = esp_timer_get_time();
    size_t bytes_written_total = 0;

    while (true) {
        int data_read = esp_http_client_read(client, (char *)buffer, buffer_size);
        if (data_read < 0) {
            ESP_LOGE(TAG, "Data read error");
            break;
        } else if (data_read == 0) {
            // EOF
            break;
        }

        err = esp_ota_write(ota_handle, buffer, data_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "esp_ota_write failed (%s)", esp_err_to_name(err));
            break;
        }

        total_read += data_read;
        bytes_written_total += data_read;

        int64_t now = esp_timer_get_time();
        if ((now - last_report_time) > 1000000LL || total_read == content_length) { // Report every second or when done
            int progress = (content_length > 0) ? (total_read * 100) / content_length : 0;
            size_t elapsed_us = now - last_report_time;
            size_t speed_bps = (elapsed_us > 0) ? (bytes_written_total * 1000000ULL) / elapsed_us : 0;

            if (progress_callback) {
                progress_callback(progress, speed_bps);
            }

            bytes_written_total = 0;
            last_report_time = now;
        }
    }

    free(buffer);
    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    if (err != ESP_OK || total_read != content_length) {
        ESP_LOGE(TAG, "Firmware download/write failed");
        esp_ota_abort(ota_handle);
        return false;
    }

    // Step 4: Finalize OTA update
    err = esp_ota_end(ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_end failed (%s)", esp_err_to_name(err));
        return false;
    }

    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed (%s)", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "OTA upgrade completed successfully. Next boot will use this image.");
    return true;
}

std::vector<int> Ota::ParseVersion(const std::string &version) {
    std::vector<int> versionComponents;
    std::stringstream ss(version);
    std::string segment;

    while (std::getline(ss, segment, '.')) {
        try {
            int num = std::stoi(segment);
            versionComponents.push_back(num);
        } catch (const std::exception&) {
            // Handle malformed version strings by treating as 0
            versionComponents.push_back(0);
        }
    }

    return versionComponents;
}

bool OtaVersionManager::IsNewVersionAvailable(const std::string& currentVersion, const std::string& newVersion) {
    // Parse both version strings into vectors of integers
    std::vector<int> currentVersionComponents = ParseVersion(currentVersion);
    std::vector<int> newVersionComponents = ParseVersion(newVersion);

    // Get the minimum length to avoid out-of-bounds access
    size_t minLen = std::min(currentVersionComponents.size(), newVersionComponents.size());

    // Compare each component sequentially
    for (size_t i = 0; i < minLen; ++i) {
        if (newVersionComponents[i] > currentVersionComponents[i]) {
            return true;  // New version is greater
        } else if (newVersionComponents[i] < currentVersionComponents[i]) {
            return false; // New version is lesser
        }
        // If equal, continue to next component
    }

    // If all compared components are equal, check the length
    // A longer version string with same prefix is considered newer
    return newVersionComponents.size() > currentVersionComponents.size();
}

