    }

    // Create JSON object
    cJSON *payload = cJSON_CreateObject();
    if (payload == nullptr) {
        ESP_LOGE(TAG, "Failed to create JSON object");
        return "{}";
    }

    // Add algorithm field
    cJSON_AddStringToObject(payload, "algorithm", "hmac-sha256");

    // Add serial number
    cJSON_AddStringToObject(payload, "serial_number", serial_number_.c_str());

    // Add challenge
    cJSON_AddStringToObject(payload, "challenge", activation_challenge_.c_str());

    // Calculate HMAC if supported
    #if SOC_HMAC_SUPPORTED
    uint8_t hmac[32];
    size_t hmac_len = sizeof(hmac);

    esp_err_t err = esp_hmac_calculate(HMAC_KEY0, activation_challenge_.c_str(), 
                                      strlen(activation_challenge_.c_str()), hmac);
    if (err == ESP_OK) {
        // Convert HMAC bytes to hex string
        char hmac_hex[65]; // 32 bytes * 2 chars per byte + null terminator
        for (int i = 0; i < 32; i++) {
            sprintf(&hmac_hex[i * 2], "%02x", hmac[i]);
        }
        hmac_hex[64] = '\0';

        cJSON_AddStringToObject(payload, "hmac", hmac_hex);
    } else {
        ESP_LOGE(TAG, "HMAC calculation failed: %s", esp_err_to_name(err));
        cJSON_Delete(payload);
        return "{}";
    }
    #endif

    // Print JSON to string
    char *json_string = cJSON_PrintUnformatted(payload);
    if (json_string == nullptr) {
        ESP_LOGE(TAG, "Failed to print JSON string");
        cJSON_Delete(payload);
        return "{}";
    }

    std::string result(json_string);

    // Log the payload for debugging
    ESP_LOGI(TAG, "Activation payload: %s", json_string);

    // Cleanup
    cJSON_Delete(payload);
    free(json_string);

    return result;
}

esp_err_t Ota::Activate() {
    // Check if we have activation challenge data to work with
    if (!has_activation_challenge_) {
        return ESP_ERR_INVALID_STATE;
    }

    // Setup HTTP client using existing infrastructure
    std::unique_ptr<HttpClient> http_client = SetupHttp();
    if (!http_client) {
        return ESP_FAIL;
    }

    // Generate the activation payload (includes HMAC signing if serial number is present)
    std::string payload = GetActivationPayload();
    if (payload.empty()) {
        return ESP_FAIL;
    }

    // Configure the HTTP request
    http_client->SetUrl("/activate");
    http_client->SetMethod("POST");
    http_client->SetHeader("Content-Type", "application/json");
    http_client->SetBody(payload);

    // Perform the HTTP request with timeout handling
    esp_err_t err = http_client->Perform(activation_timeout_ms_);
    if (err != ESP_OK) {
        if (err == ESP_ERR_TIMEOUT) {
            return ESP_ERR_TIMEOUT;
        }
        return ESP_FAIL;
    }

    // Check HTTP response status
    int status_code = http_client->GetResponseStatusCode();
    if (status_code == 200) {
        // Successful activation
        return ESP_OK;
    } else if (status_code == 401) {
        // Unauthorized - invalid signature or challenge
        return ESP_ERR_INVALID_CRC;
    } else {
        // Other HTTP errors
        return ESP_FAIL;
    }
}

