std::string Settings::GetString(const std::string &key, const std::string &default_value) {
    // Check if NVS handle is valid
    if (nvs_handle_ == 0) {
        return default_value;
    }

    // First call to get the required length
    size_t required_size = 0;
    esp_err_t err = nvs_get_str(nvs_handle_, key.c_str(), nullptr, &required_size);

    // If key doesn't exist or other error, return default value
    if (err != ESP_OK || required_size == 0) {
        return default_value;
    }

    // Allocate buffer to hold the string
    std::string result;
    result.resize(required_size);

    // Second call to get the actual string data
    err = nvs_get_str(nvs_handle_, key.c_str(), &result[0], &required_size);

    // Check for errors
    if (err != ESP_OK) {
        return default_value;
    }

    // Resize to actual length and remove trailing null terminator if present
    if (!result.empty() && result.back() == '\0') {
        result.pop_back();
    }

    return result;
}

