bool Settings::GetBool(const std::string &key, bool default_value) {
    // Check if NVS handle is valid
    if (!nvs_handle_) {
        return default_value;
    }

    uint8_t value = 0;
    esp_err_t err = nvs_get_u8(nvs_handle_, key.c_str(), &value);

    // If successful, convert uint8_t to bool (non-zero = true, zero = false)
    if (err == ESP_OK) {
        return value != 0;
    }

    // On error or key not found, return the default value
    return default_value;
