Es8388AudioCodec::Es8388AudioCodec(
    void *i2c_master_handle,
    i2c_port_t i2c_port,
    int input_sample_rate,
    int output_sample_rate,
    gpio_num_t mclk_pin,
    gpio_num_t bclk_pin,
    gpio_num_t ws_pin,
    gpio_num_t dout_pin,
    gpio_num_t din_pin,
    gpio_num_t pa_pin,
    uint8_t i2c_addr,
    bool enable_pa)
    : input_sample_rate_(input_sample_rate),
      output_sample_rate_(output_sample_rate),
      pa_enabled_(enable_pa),
      pa_pin_(pa_pin) {

    assert(input_sample_rate == output_sample_rate && "Input and Output Sample Rates must be equal");

    // Step 1: Initialize I2C Control Interface
    i2c_ctrl_ = audio_codec_new_i2c_ctrl(i2c_port, i2c_addr, i2c_master_handle);
    if (!i2c_ctrl_) {
        return; // Failed to create I2C controller
    }

    // Step 2: Initialize GPIO for PA if required
    if (pa_enabled_) {
        gpio_if_ = audio_codec_new_gpio();
        if (gpio_if_) {
            gpio_if_->setup(pa_pin_, GPIO_MODE_OUTPUT);
            gpio_if_->set(pa_pin_, 0); // Initially off
        }
    } else {
        gpio_if_ = nullptr;
    }

    // Step 3: Create Duplex I2S Channels
    i2s_data_ = CreateDuplexChannels(mclk_pin, bclk_pin, ws_pin, dout_pin, din_pin);
    if (!i2s_data_) {
        return; // Failed to create I2S data interface
    }

    // Step 4: Initialize ES8388 Codec Driver
    codec_driver_ = es8388_codec_new(i2c_ctrl_);
    if (!codec_driver_) {
        return; // Failed to initialize codec driver
    }

    // Step 5: Create Input & Output Device Handles
    tx_dev_ = esp_codec_dev_new(codec_driver_, i2s_data_);
    rx_dev_ = esp_codec_dev_new(codec_driver_, i2s_data_);

    if (!tx_dev_ || !rx_dev_) {
        return; // Failed to create device handles
    }
}

