    i2s_std_config_t std_cfg = {
        .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(48000), // Assume 48kHz sample rate
        .slot_cfg = I2S_STD_PHILIP_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO),
        .gpio_cfg = {
            .mclk = mclk,
            .bclk = bclk,
            .ws = ws,
            .dout = dout,
            .din = I2S_GPIO_UNUSED,
            .invert_flags = {
                .mclk_inv = false,
                .bclk_inv = false,
                .ws_inv = false,
            },
        },
    };

    ret = i2s_channel_init_std_mode(tx_handle, &std_cfg);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize TX channel in standard mode");
        i2s_del_channel(tx_handle);
        return ret;
    }

    // Create RX channel
    i2s_chan_handle_t rx_handle = NULL;
    ret = i2s_new_channel(&chan_cfg, NULL, &rx_handle);
    if (ret != ESP_OK || !rx_handle) {
        ESP_LOGE(TAG, "Failed to create RX channel");
        i2s_del_channel(tx_handle);
        return ret;
    }

    // TDM mode config for RX
    i2s_tdm_config_t tdm_cfg = {
        .clk_cfg = I2S_TDM_CLK_DEFAULT_CONFIG(48000), // Same sample rate
        .slot_cfg = I2S_TDM_PHILIP_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO, I2S_TDM_SLOT0 | I2S_TDM_SLOT1),
        .gpio_cfg = {
            .mclk = mclk,
            .bclk = bclk,
            .ws = ws,
            .dout = I2S_GPIO_UNUSED,
            .din = din,
            .invert_flags = {
                .mclk_inv = false,
                .bclk_inv = false,
                .ws_inv = false,
            },
        },
    };

    ret = i2s_channel_init_tdm_mode(rx_handle, &tdm_cfg);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize RX channel in TDM mode");
        i2s_del_channel(tx_handle);
        i2s_del_channel(rx_handle);
        return ret;
    }

    ESP_LOGI(TAG, "Duplex channels created");

    // At this point, tx_handle and rx_handle are ready for use elsewhere
    // They can now be passed to audio_codec_new_i2s_data()

    return ESP_OK;
}

void Es8388AudioCodec::SetOutputVolume(int volume) {
    // Call parent implementation to handle logging and storage
    AudioCodec::SetOutputVolume(volume);

    // Apply volume to hardware if output device is already open
    if (output_dev_ != nullptr) {
        std::lock_guard<std::mutex> lock(data_if_mutex_);
        esp_codec_dev_set_out_vol(output_dev_, volume);
    }
}

esp_err_t Es8388AudioCodec::EnableInput(bool enable) {
    // Early return if no state change is needed
    if (enable == input_enabled_) {
        return ESP_OK;
    }

    std::lock_guard<std::mutex> lock(api_mutex_);

    esp_err_t ret = ESP_OK;

    if (enable) {
        // Configure sample format
        esp_codec_dev_sample_info_t fs = {
            .sample_rate = input_sample_rate_,
            .channel = input_channels_,
            .bits_per_sample = 16, // Fixed at 16 bits as per design
        };

        // Open input device
        ret = esp_codec_dev_open(input_dev_, &fs);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to open ES8388 input device");
            return ret;
        }

        // Apply input gain setting
        ret = esp_codec_dev_set_in_gain(input_dev_, input_gain_);
        if (ret != ESP_OK) {
            ESP_LOGW(TAG, "Failed to set input gain, err = %d", ret);
        }
    } else {
        // Close input device
        ret = esp_codec_dev_close(input_dev_);
        if (ret != ESP_OK) {
            ESP_LOGE(TAG, "Failed to close ES8388 input device");
        }
    }

    // Update internal flag and log status through parent class
    AudioCodec::EnableInput(enable);

    return ret;
}

bool Es8374AudioCodec::EnableOutput(bool enable) {
    std::lock_guard<std::mutex> lock(data_if_mutex_);

    // If already in desired state, return success
    if ((enable && output_enabled_) || (!enable && !output_enabled_)) {
        return true;
    }

    if (enable) {
        // Enable output device
        if (output_dev_ == nullptr) {
            return false;
        }

        // Configure device parameters
        esp_codec_dev_cfg_t cfg = {};
        cfg.sample_rate = sample_rate_;
        cfg.channel = ESP_CODEC_DEV_CH_MONO; // or ESP_CODEC_DEV_CH_STEREO based on configuration
        cfg.bit_width = ESP_CODEC_DEV_BIT_WIDTH_16BIT;

        // Open the output device
        esp_err_t ret = esp_codec_dev_open(output_dev_, &cfg);
        if (ret != ESP_OK) {
            return false;
        }

        output_enabled_ = true;
    } else {
        // Disable output device
        if (output_dev_ != nullptr) {
            esp_codec_dev_close(output_dev_);
        }
        output_enabled_ = false;
    }

    return true;
}

int Es8388AudioCodec::Read(int16_t* dest, int samples) {
    // Validate input parameters
    if (!dest || samples <= 0) {
        return 0;
    }

    // Check if input device is initialized
    if (!input_dev_) {
        return 0;
    }

    // Check if input is enabled
    if (!input_enabled_) {
        return 0;
    }

    // Acquire mutex for thread safety if needed
    if (data_if_mutex_) {
        xSemaphoreTakeRecursive(data_if_mutex_, portMAX_DELAY);
    }

    // Perform the actual read operation
    int bytes_to_read = samples * sizeof(int16_t);
    int bytes_read = esp_codec_dev_read(input_dev_, (void*)dest, bytes_to_read);

    // Release mutex
    if (data_if_mutex_) {
        xSemaphoreGiveRecursive(data_if_mutex_);
    }

    // Convert bytes read back to samples and return
    if (bytes_read < 0) {
        return 0;
    }

    return bytes_read / sizeof(int16_t);
}

int Es8388AudioCodec::Write(const int16_t *data, int samples) {
    // Check if output is enabled before attempting to write
    if (!output_enabled_) {
        return 0;
    }

    // Check for valid parameters
    if (data == nullptr || samples <= 0) {
        return 0;
    }

    // Protect against concurrent access if needed
    std::lock_guard<std::mutex> lock(write_mutex_);

    // Calculate the number of bytes to write (16-bit samples)
    size_t bytes_to_write = samples * sizeof(int16_t);

    // Write data to the output device
    esp_err_t result = esp_codec_dev_write(output_dev_, data, bytes_to_write);

    // Handle potential errors without aborting
    ESP_ERROR_CHECK_WITHOUT_ABORT(result);

    // Return the number of samples written (0 if error occurred)
    if (result == ESP_OK) {
        return samples;
    } else {
        return 0;
    }
}

AudioDebugger::AudioDebugger() : udp_sockfd_(-1) {
    // Initialize the UDP socket file descriptor to -1 indicating no socket

#ifdef CONFIG_USE_AUDIO_DEBUGGER
    // Only proceed with UDP setup if audio debugging is enabled

    // Create UDP socket
    udp_sockfd_ = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (udp_sockfd_ < 0) {
        ESP_LOGE("AudioDebugger", "Failed to create UDP socket: %s", strerror(errno));
        return;
    }

    // Configure server address structure
    memset(&udp_server_addr_, 0, sizeof(udp_server_addr_));
    udp_server_addr_.sin_family = AF_INET;
    udp_server_addr_.sin_port = htons(CONFIG_AUDIO_DEBUG_UDP_PORT);  // Assuming port config exists

    // Convert server IP address from string to binary form
    if (inet_aton(CONFIG_AUDIO_DEBUG_UDP_SERVER, &udp_server_addr_.sin_addr) == 0) {
        ESP_LOGE("AudioDebugger", "Invalid server IP address: %s", CONFIG_AUDIO_DEBUG_UDP_SERVER);
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }

    ESP_LOGI("AudioDebugger", "Initialized UDP debugger to %s:%d", 
             CONFIG_AUDIO_DEBUG_UDP_SERVER, CONFIG_AUDIO_DEBUG_UDP_PORT);
#endif
}

AudioDebugger::~AudioDebugger() {
#ifdef CONFIG_USE_AUDIO_DEBUGGER
    if (udp_sockfd_ != -1) {
        int result = close(udp_sockfd_);
        if (result == 0) {
            ESP_LOGI("AudioDebugger", "UDP socket closed successfully");
        } else {
            ESP_LOGW("AudioDebugger", "Failed to close UDP socket: errno %d", errno);
        }
        udp_sockfd_ = -1;
    }
#endif
}

void AudioDebugger::Feed(const std::vector<int16_t>& audio_data) {
    // Check if socket is valid
    if (udp_sockfd_ < 0) {
        ESP_LOGW("AudioDebugger", "UDP socket not initialized");
        return;
    }

    // Check if we have data to send
    if (audio_data.empty()) {
        return;
    }

    // Parse server configuration
    std::string server_config = CONFIG_AUDIO_DEBUG_UDP_SERVER;
    size_t colon_pos = server_config.find(':');
    if (colon_pos == std::string::npos) {
        ESP_LOGW("AudioDebugger", "Invalid server configuration format");
        return;
    }

    std::string ip_address = server_config.substr(0, colon_pos);
    int port = std::stoi(server_config.substr(colon_pos + 1));

    // Prepare socket address structure
    struct sockaddr_in server_addr;
    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(port);
    inet_pton(AF_INET, ip_address.c_str(), &server_addr.sin_addr);

    // Acquire lock for thread safety
    std::lock_guard<std::mutex> lock(mutex_);

    // Send data via UDP
    ssize_t sent_bytes = sendto(udp_sockfd_, 
                               audio_data.data(), 
                               audio_data.size() * sizeof(int16_t), 
                               0,
                               (struct sockaddr*)&server_addr, 
                               sizeof(server_addr));

    if (sent_bytes < 0) {
        ESP_LOGW("AudioDebugger", "Failed to send audio data: %s", strerror(errno));
    } else {
        ESP_LOGD("AudioDebugger", "Sent %d bytes of audio data", sent_bytes);
    }
}

