void AfeWakeWord::Initialize(AudioCodec* codec, srmodel_list_t* models_list) {
    // Step 1: Initialize model list if not provided
    if (models_list == nullptr) {
        models_list_ = esp_srmodel_init(const_cast<char*>("model"));
    } else {
        models_list_ = models_list;
    }

    // Step 2: Filter required models (Noise Suppression and VAD)
    ns_model_ = esp_srmodel_filter(models_list_, ESP_SR_MODEL_NS);
    vad_model_ = esp_srmodel_filter(models_list_, ESP_SR_MODEL_VAD);

    // Step 3: Setup AFE configuration
    afe_config_t config = afe_config_init();
    config.afe_mode = AFE_MODE_HIGH_PERF;
    config.type = AFE_TYPE_SR;
    config.ns_model = ns_model_;
    config.vad_model = vad_model_;
    config.aec_mode = false; // Assuming no Acoustic Echo Cancellation needed unless specified
    config.prefer_core = 1;  // Prefer running on core 1
    config.malloc_place = malloc_place_ram; // Or malloc_place_psram depending on memory constraints
    config.input_format = static_cast<afe_input_mode_t>(codec->GetNumChannels()); // Derive from codec

    // Step 4: Create AFE handler and instance
    afe_handler_ = esp_afe_handle_from_config(&config);
    afe_data_instance_ = afe_iface_->create_from_config(afe_handler_, &config);

    // Step 5: Launch the audio detection FreeRTOS task
    xTaskCreate(
        AudioDetectionTask,
        "audio_detection",
        4096,
        this,
        3,
        &audio_detection_task_handle_
    );
}

