void AFEWakeWord::AudioDetectionTask() {
    while (true) {
        // Wait for the detection running event bit to be set
        EventBits_t bits = xEventGroupWaitBits(
            event_group_,
            DETECTION_RUNNING_EVENT,
            pdFALSE,  // Clear bits on exit = false
            pdTRUE,   // Wait for all bits = true
            portMAX_DELAY
        );

        // Check if we have the running event bit set
        if (bits & DETECTION_RUNNING_EVENT) {
            // Perform wake word detection
            int result = afe_iface_->detect(afe_data_);

            // Check if wake word was detected (non-negative result)
            if (result >= 0) {
                // Store the pre-detection audio data (last ~2 seconds)
                StoreWakeWordData(nullptr, 0); // This will store buffered data

                // Update last detected wake word with thread safety
                BaseType_t yield_required = pdFALSE;
                if (mutex_ != nullptr) {
                    if (xSemaphoreTake(mutex_, (TickType_t)10) == pdTRUE) {
                        last_detected_wake_word_ = result;
                        xSemaphoreGive(mutex_);
                    }
                } else {
                    last_detected_wake_word_ = result;
                }

                // Trigger the wake word detected callback if registered
                if (wake_word_detected_callback_ != nullptr) {
                    wake_word_detected_callback_(result);
                }

                // Log the detection for monitoring purposes
                ESP_LOGI("AFEWakeWord", "Wake word detected: %d", result);
            }

            // Small delay to prevent busy looping and allow other tasks to run
            vTaskDelay(pdMS_TO_TICKS(10));
        } else {
            // If somehow we don't have the right bits, small delay to prevent busy loop
            vTaskDelay(pdMS_TO_TICKS(100));
        }
    }
}

void AfeWakeWord::StoreWakeWordData(const int16_t* data, size_t samples) {
    // Store the incoming PCM data as a new vector in the deque
    wake_word_pcm_.emplace_back(std::vector<int16_t>(data, data + samples));

    // Maintain buffer size to prevent unbounded memory usage
    // Keep approximately 2 seconds of audio data (67 chunks for 30ms @ 16kHz)
    const size_t kMaxBufferChunks = 67;
    while (wake_word_pcm_.size() > kMaxBufferChunks) {
        wake_word_pcm_.pop_front();
    }
}

void OpusCodecHandler::EncodeWakeWordData() {
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    if (wake_word_pcm_.empty()) {
        return;
    }

    // Calculate frame size based on sample rate and frame duration
    const int sample_rate = 16000; // As per InitializeAudioCodec
    const int channels = 1;        // Mono as per InitializeAudioCodec
    const int frame_size = (sample_rate * OPUS_FRAME_DURATION_MS) / 1000;

    // Process all available PCM data
    size_t total_samples = wake_word_pcm_.size();
    size_t processed_samples = 0;

    while (processed_samples + frame_size <= total_samples) {
        // Prepare input data for encoding
        const int16_t* input_frame = wake_word_pcm_.data() + processed_samples;

        // Encode the frame
        std::vector<uint8_t> encoded_data(MAX_OPUS_PACKET_SIZE);
        int encoded_bytes = opus_encoder_->Encode(input_frame, frame_size, encoded_data.data(), encoded_data.size());

        if (encoded_bytes > 0) {
            // Resize to actual encoded size
            encoded_data.resize(encoded_bytes);

            // Package into AudioStreamPacket (following ProcessEncodeTask pattern)
            AudioStreamPacket packet;
            packet.codec_type = AUDIO_CODEC_OPUS;
            packet.data = std::move(encoded_data);
            packet.timestamp = GetCurrentTimestamp();

            // Store or queue the encoded packet
            wake_word_opus_packets_.push_back(std::move(packet));
        }

        processed_samples += frame_size;
    }

    // Remove processed PCM data, keep any remaining partial frame
    if (processed_samples > 0) {
        wake_word_pcm_.erase(wake_word_pcm_.begin(), wake_word_pcm_.begin() + processed_samples);
    }

    // Notify waiting threads that encoded data is available
    wake_word_cond_var_.notify_all();
}

bool AfeWakeWord::GetWakeWordOpus(std::vector<uint8_t>& opus_data) {
    std::unique_lock<std::mutex> lock(wake_word_mutex_);

    // Wait until there's data available or termination marker
    wake_word_cv_.wait(lock, [this] { 
        return !wake_word_opus_.empty(); 
    });

    // Get the front packet
    auto& packet = wake_word_opus_.front();

    // Check if this is a termination marker (empty vector)
    if (packet.empty()) {
        wake_word_opus_.pop_front();
        return false;
    }

    // Move the data to the output parameter
    opus_data = std::move(packet);
    wake_word_opus_.pop_front();

    return true;
}

CustomWakeWord::~CustomWakeWord() {
    // Signal any running tasks to stop before cleaning up shared resources
    wake_word_running_ = false;

    // Wake up any waiting threads to allow them to exit gracefully
    pthread_cond_broadcast(&wake_word_cv_);

    // Wait for the encoding task to complete if it's running
    if (wake_word_encode_task_handle_ != nullptr) {
        vTaskDelete(wake_word_encode_task_handle_);
        wake_word_encode_task_handle_ = nullptr;
    }

    // Clean up the multinet model if it was initialized
    if (multinet_ != nullptr && multinet_model_data_ != nullptr) {
        multinet_->destroy(multinet_model_data_);
        multinet_model_data_ = nullptr;
        multinet_ = nullptr;
    }

    // Deinitialize speech recognition models
    if (models_ != nullptr) {
        esp_srmodel_deinit(models_);
        models_ = nullptr;
    }

    // Free custom allocated memory buffers
    if (wake_word_encode_task_stack_ != nullptr) {
        heap_caps_free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
    }

    if (wake_word_encode_task_buffer_ != nullptr) {
        heap_caps_free(wake_word_encode_task_buffer_);
        wake_word_encode_task_buffer_ = nullptr;
    }

    // Clear audio buffers
    wake_word_pcm_.clear();
    wake_word_opus_.clear();

    // Destroy synchronization primitives
    pthread_mutex_destroy(&wake_word_mutex_);
    pthread_cond_destroy(&wake_word_cv_);
}

void CustomWakeWord::ParseWakenetModelConfig(srmodel_list_t* models_list) {
    if (models_list == nullptr) {
        ESP_LOGE(TAG, "Invalid models list provided");
        return;
    }

    for (int i = 0; i < models_list->num; i++) {
        const char* model_name = models_list->model_name[i];

        // Check if this is a wakenet model (similar to ESP_WN_PREFIX check)
        if (model_name != nullptr && strncmp(model_name, ESP_WN_PREFIX, strlen(ESP_WN_PREFIX)) == 0) {
            ESP_LOGI(TAG, "Found wakenet model: %s", model_name);

            // Extract wake words for this model
            char* wake_words = esp_srmodel_get_wake_words(model_name);
            if (wake_words != nullptr) {
                ESP_LOGI(TAG, "Loaded wake words: %s", wake_words);

                // Parse and store wake words/commands
                // This would typically involve splitting the comma-separated string
                // and populating the commands_ vector or similar structure
                ParseAndStoreCommands(wake_words);

                // Free the allocated memory for wake_words if needed
                // free(wake_words); // Only if the API requires manual freeing

                // Extract language information if available
                char* language = esp_srmodel_get_language(model_name);
                if (language != nullptr) {
                    language_ = std::string(language);
                    ESP_LOGI(TAG, "Model language: %s", language_.c_str());
                    // free(language); // Only if required
                }

                // Extract threshold information if available
                float threshold = esp_srmodel_get_threshold(model_name);
                if (threshold > 0) {
                    threshold_ = threshold;
                    ESP_LOGI(TAG, "Model threshold: %f", threshold_);
                }
            } else {
                ESP_LOGW(TAG, "No wake words found for model: %s", model_name);
            }
        }
    }
}

