void WakeWordDetector::Feed(const std::vector<int16_t>& data) {
    // Store the incoming audio data for potential encoding later
    StoreWakeWordData(data);

    // Run wake word detection on the incoming PCM data
    esp_mn_state_t state = multinet_->detect(multinet_model_data_, data.data(), data.size());

    // Handle different detection states
    switch (state) {
        case ESP_MN_STATE_DETECTING:
            // Still in detection phase, continue processing
            break;

        case ESP_MN_STATE_DETECTED: {
            // A wake word has been detected
            // Get the detection result
            auto result = multinet_->get_detection_result(multinet_model_data_);

            // Check if it's a valid wake word action
            if (result && strcmp(result->text, "wake") == 0) {
                // Stop further processing
                multinet_->stop(multinet_model_data_);

                // Update last detected wake word
                last_detected_wake_word_ = result->text;

                // Encode the buffered audio data if needed
                EncodeWakeWordData();

                // Trigger the wake word detected callback if registered
                if (wake_word_detected_callback_) {
                    wake_word_detected_callback_(result->text);
                }

                // Notify any registered listeners
                OnWakeWordDetected(result->text);
            }
            break;
        }

        case ESP_MN_STATE_TIMEOUT:
            // Detection timed out, reset or restart as needed
            multinet_->stop(multinet_model_data_);
            // Clear buffered audio data
            {
                std::lock_guard<std::mutex> lock(wake_word_buffer_mutex_);
                wake_word_pcm_.clear();
                wake_word_opus_.clear();
            }
            break;

        default:
            // Handle other states or errors if necessary
            break;
    }
}

