void OpusCodecHandler::EncodeWakeWordData() {
    // Lock mutex to protect shared resources
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Check if we have PCM data to encode
    if (wake_word_pcm_.empty()) {
