bool ReceiveWifiCredentialsFromAudio(Application* app, 
                                   WifiManager* wifi_manager, 
                                   Display* display,
                                   size_t timeout_ms) {
    // Get audio service
    auto& audio_service = app->GetAudioService();

    // Initialize audio processing components
    AudioSignalProcessor signal_processor;
    AudioDataBuffer data_buffer;

    // Configure audio parameters
    const size_t kAudioSampleRate = 16000;  // 16kHz input sample rate
    const size_t kTargetSampleRate = 6400;  // 6.4kHz target rate
    const size_t kDownsampleStep = kAudioSampleRate / kTargetSampleRate;  // = 2.5, but we'll use integer approximation
    const size_t kSamplesPerRead = 512;
    const size_t kMonoChannels = 1;
    const size_t kStereoChannels = 2;

    // Allocate buffer for audio samples
    std::vector<int16_t> audio_buffer(kSamplesPerRead * kStereoChannels);
    std::vector<int16_t> mono_buffer(kSamplesPerRead);

    // Timing control
    const auto start_time = std::chrono::steady_clock::now();
    const auto timeout_duration = std::chrono::milliseconds(timeout_ms);

    // Main processing loop
    while (true) {
        // Check timeout
        auto current_time = std::chrono::steady_clock::now();
        if (std::chrono::duration_cast<std::chrono::milliseconds>(current_time - start_time) > timeout_duration) {
            return false;
        }

        // Check if we're still in the correct state
        if (app->GetDeviceState() != kDeviceStateWifiConfiguring) {
            return false;
        }

        // Read audio data
        size_t samples_read = 0;
        if (!audio_service.ReadAudioData(audio_buffer.data(), kSamplesPerRead * kStereoChannels, &samples_read)) {
            continue; // Try again on read failure
        }

        if (samples_read == 0) {
            continue; // No data available, try again
        }

        // Convert to mono if needed (stereo to mono conversion)
        size_t actual_samples = samples_read / kStereoChannels;
        if (kStereoChannels == 2) {
            for (size_t i = 0; i < actual_samples; ++i) {
                // Average left and right channels
                mono_buffer[i] = (audio_buffer[i * 2] + audio_buffer[i * 2 + 1]) / 2;
            }
        } else {
            // Already mono, just copy
            std::copy(audio_buffer.begin(), audio_buffer.begin() + actual_samples, mono_buffer.begin());
        }

        // Downsample from 16kHz to 6.4kHz
        size_t downsampled_count = 0;
        for (size_t i = 0; i < actual_samples; i += kDownsampleStep) {
            if (downsampled_count < mono_buffer.size()) {
                // Simple downsampling - take every nth sample
                mono_buffer[downsampled_count++] = mono_buffer[i];
            }
        }

        // Process each downsampled sample through AFSK demodulator
        for (size_t i = 0; i < downsampled_count; ++i) {
            // Get bit probability from signal processor
            float bit_probability = signal_processor.ProcessSample(mono_buffer[i]);

            // Feed probability to data buffer for reconstruction
            if (data_buffer.AddBitProbability(bit_probability)) {
                // Complete frame received, try to extract credentials
                std::string received_data = data_buffer.GetDecodedData();
                if (!received_data.empty()) {
                    // Parse SSID and password (separated by newline)
                    size_t newline_pos = received_data.find('\n');
                    if (newline_pos != std::string::npos) {
                        std::string ssid = received_data.substr(0, newline_pos);
                        std::string password = received_data.substr(newline_pos + 1);

                        // Validate and save credentials
                        if (!ssid.empty() && !password.empty()) {
                            // Save credentials using SsidManager
                            SsidManager::GetInstance().AddSsid(ssid, password);

                            // Stop configuration AP mode
                            wifi_manager->StopConfigAp();

                            return true; // Success
                        }
                    }
                }

                // Reset buffer for next transmission
                data_buffer.Reset();
            }
        }
    }

    return false; // Should not reach here due to timeout check
}

FrequencyDetector::FrequencyDetector(float frequency, size_t window_size) 
    : frequency_(frequency)
    , window_size_(window_size)
    , angular_frequency_(2.0f * M_PI * frequency)
    , cos_coefficient_(std::cos(angular_frequency_))
    , sin_coefficient_(std::sin(angular_frequency_))
    , filter_coefficient_(2.0f * cos_coefficient_)
{
    // Initialize state buffer with two zeros
    state_buffer_[0] = 0.0f;
    state_buffer_[1] = 0.0f;
}

void FrequencyDetector::Reset() {
    state_buffer_.clear();
    state_buffer_.push_back(0.0f);
    state_buffer_.push_back(0.0f);
}

void FrequencyDetector::ProcessSample(float sample) {
    // Compute new state using Goertzel recurrence relation
    float s_new = sample + filter_coefficient_ * state_buffer_[1] - state_buffer_[0];

    // Update the state buffer: shift older states back
    state_buffer_[0] = state_buffer_[1];
    state_buffer_[1] = s_new;
}

float FrequencyDetector::GetAmplitude() const {
    // Check if we have enough states in the buffer
    if (state_buffer_.size() < 2) {
        return 0.0f;
    }

    // Get the last two states from the buffer
    float s_prev = state_buffer_[state_buffer_.size() - 2];  // S[-2]
    float s_curr = state_buffer_[state_buffer_.size() - 1];  // S[-1]

    // Calculate amplitude using Goertzel algorithm formula
    // magnitude = sqrt(S[-1]^2 + S[-2]^2 - S[-1] * S[-2] * 2 * cos(ω))
    float real_part = s_curr - s_prev * cos_coefficient_;
    float imag_part = s_prev * sin_coefficient_;
    float magnitude_squared = real_part * real_part + imag_part * imag_part;

    // Take square root and normalize
    float amplitude = sqrt(magnitude_squared);
    return amplitude / (window_size_ / 2.0f);
}

std::vector<float> AudioSignalProcessor::ProcessAudioSamples(const std::vector<float>& samples) {
    std::vector<float> probabilities;

    for (const auto& sample : samples) {
        // Add new sample to buffer (maintains sliding window)
        input_buffer_.push_back(sample);

        // If buffer exceeds window size, remove oldest sample
        if (input_buffer_.size() > window_size_) {
            input_buffer_.pop_front();
        }

        // When we have accumulated enough samples for one bit
        if (input_buffer_.size() >= samples_per_bit_) {
            // Only process when we have exactly the right amount or at bit boundaries
            if ((input_buffer_.size() - samples_per_bit_) % 1 == 0 || input_buffer_.size() == samples_per_bit_) {
                // Process the current window with both detectors
                float mark_amplitude = mark_detector_.DetectFrequency(input_buffer_);
                float space_amplitude = space_detector_.DetectFrequency(input_buffer_);

                // Calculate total amplitude with epsilon to prevent division by zero
                float total_amplitude = mark_amplitude + space_amplitude;
                const float epsilon = 1e-10f;

                // Compute probability as normalized ratio of mark amplitude
                float probability = 0.0f;
                if (total_amplitude > epsilon) {
                    probability = mark_amplitude / total_amplitude;
                }

                // Clamp probability between 0 and 1
                if (probability < 0.0f) probability = 0.0f;
                if (probability > 1.0f) probability = 1.0f;

                probabilities.push_back(probability);

                // Reset detectors for next window processing
                mark_detector_.Reset();
                space_detector_.Reset();
            }
        }
    }

    return probabilities;
}

