        uint8_t bit = (prob > threshold) ? 1 : 0;

        switch (data_reception_state_) {
            case DataReceptionState::kInactive:
                // Shift identifier buffer and add new bit
                identifier_buffer_ <<= 1;
                identifier_buffer_ |= bit;

                // Check if we've detected the start of transmission pattern
                if (identifier_buffer_ == start_of_transmission_) {
                    data_reception_state_ = DataReceptionState::kWaiting;
                    identifier_buffer_ = 0; // Reset for end detection
                    bit_buffer_.clear();    // Clear any previous bit data
                }
                break;

            case DataReceptionState::kWaiting:
