                        if (checksum_enabled_) {
                            size_t checksum_pos = payload.find_last_of(checksum_delimiter_);
                            if (checksum_pos != std::string::npos) {
                                std::string data_part = payload.substr(0, checksum_pos);
                                std::string checksum_part = payload.substr(checksum_pos + 1);
                                uint8_t calculated_checksum = CalculateChecksum(data_part);
                                uint8_t received_checksum = static_cast<uint8_t>(std::stoi(checksum_part));
