std::vector<uint8_t> AudioDataBuffer::ConvertBitsToBytes(const std::vector<uint8_t>& bits) const {
    std::vector<uint8_t> bytes;

    // Calculate number of complete bytes we can form
    size_t num_bytes = bits.size() / 8;

    // Reserve space to avoid repeated allocations
    bytes.reserve(num_bytes + (bits.size() % 8 ? 1 : 0));

    // Process complete bytes
    for (size_t i = 0; i < num_bytes; ++i) {
        uint8_t byte = 0;
        // Assuming MSB-first bit ordering (most common in communication protocols)
        for (int bit_pos = 0; bit_pos < 8; ++bit_pos) {
            uint8_t bit_value = bits[i * 8 + bit_pos];
            if (bit_value) {
                byte |= (1 << (7 - bit_pos));
            }
        }
        bytes.push_back(byte);
    }

    // Handle remaining bits (padding with zeros)
    size_t remaining_bits = bits.size() % 8;
    if (remaining_bits > 0) {
        uint8_t byte = 0;
        for (size_t i = 0; i < remaining_bits; ++i) {
            uint8_t bit_value = bits[num_bytes * 8 + i];
            if (bit_value) {
                byte |= (1 << (7 - i));
            }
        }
        // Remaining bit positions are implicitly zero
        bytes.push_back(byte);
    }

    return bytes;
}

