    // step_ can be positive or negative depending on fade direction
    brightness_ += step_;

    // Boundary checking to ensure we don't overshoot target
    if ((step_ > 0 && brightness_ >= target_brightness_) || 
        (step_ < 0 && brightness_ <= target_brightness_)) {
