std::string GetSystemInfoJson() {
    std::string json = "{";

    // Add board metadata
    json += "\"board\":";
    json += Board::GetBoardJson();
    json += ",";

    // Add system information
    json += "\"chip_model\":\"" + SystemInfo::GetChipModelName() + "\",";
    json += "\"mac_address\":\"" + SystemInfo::GetMacAddress() + "\",";
    json += "\"user_agent\":\"" + SystemInfo::GetUserAgent() + "\",";

    // Add memory information
    json += "\"flash_size\":" + std::to_string(SystemInfo::GetFlashSize()) + ",";
    json += "\"free_heap\":" + std::to_string(SystemInfo::GetFreeHeapSize()) + ",";
    json += "\"min_free_heap\":" + std::to_string(SystemInfo::GetMinimumFreeHeapSize()) + ",";

    // Add display information
    auto display = Board::GetDisplay();
    if (display) {
        json += "\"display\":{";
        json += "\"type\":\"" + (dynamic_cast<OledDisplay*>(display.get()) ? std::string("OLED") : std::string("LCD")) + "\",";
        json += "\"width\":" + std::to_string(display->GetWidth()) + ",";
        json += "\"height\":" + std::to_string(display->GetHeight());
        json += "},";
    }

    // Add OTA partition information
    const esp_partition_t* running_partition = esp_ota_get_running_partition();
    if (running_partition) {
        json += "\"ota_partition\":{";
        json += "\"name\":\"" + std::string(running_partition->label) + "\",";
        json += "\"address\":" + std::to_string(running_partition->address) + ",";
        json += "\"size\":" + std::to_string(running_partition->size);
        json += "},";
    }

    // Add flash partition list
    json += "\"partitions\":[";
    esp_partition_iterator_t iterator = esp_partition_find(ESP_PARTITION_TYPE_ANY, ESP_PARTITION_SUBTYPE_ANY, nullptr);
    bool first_partition = true;
    while (iterator != nullptr) {
        const esp_partition_t* partition = esp_partition_get(iterator);
        if (!first_partition) {
            json += ",";
        }
        json += "{";
        json += "\"type\":" + std::to_string(partition->type) + ",";
        json += "\"subtype\":" + std::to_string(partition->subtype) + ",";
        json += "\"name\":\"" + std::string(partition->label) + "\",";
        json += "\"address\":" + std::to_string(partition->address) + ",";
        json += "\"size\":" + std::to_string(partition->size) + ",";
        json += "\"encrypted\":" + std::string(partition->encrypted ? "true" : "false");
        json += "}";
        first_partition = false;
        iterator = esp_partition_next(iterator);
    }
    esp_partition_iterator_release(iterator);
    json += "],";

    // Remove trailing comma if exists and close JSON
    if (json.back() == ',') {
        json.pop_back();
    }
    json += "}";

    return json;
}

