void WifiBoard::TryWifiConnect() {
    // Check if already connected or in config mode - avoid unnecessary reconnection attempts
    if (WifiManager::GetInstance().IsConnected()) {
        return;
    }

    if (WifiManager::GetInstance().IsConfigMode()) {
        return;
    }

    // Stop any existing station connection attempts
    WifiManager::GetInstance().StopStation();

    // Start the connection timeout timer before attempting connection
    if (connect_timer_ != nullptr) {
        esp_timer_stop(connect_timer_);
    } else {
        // Create timer if it doesn't exist
        esp_timer_create_args_t timer_args = {};
        timer_args.callback = &WifiBoard::OnWifiConnectTimeoutCallback;
        timer_args.arg = this;
        timer_args.name = "wifi_connect_timeout";
        esp_timer_create(&timer_args, &connect_timer_);
    }

    // Start the timeout timer - CONNECT_TIMEOUT_SEC converted to microseconds
    esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000);

    // Register event callback to handle network events
    WifiManager::GetInstance().SetEventCallback(
        [this](NetworkEvent event) {
            this->OnNetworkEvent(event);
        }
    );

    // Attempt to connect to the configured Wi-Fi network
    WifiManager::GetInstance().StartStation();
}

void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string& data) {
    // Store the current network state
    current_network_state_ = event;

    // Handle different network events
    switch (event) {
        case NetworkEvent::kScanningStarted:
            // Network scanning has started
            LOG(INFO) << "WiFi scanning started";
            // Could update UI to show scanning indicator
            break;

        case NetworkEvent::kScanningFinished:
            // Network scanning has completed
            LOG(INFO) << "WiFi scanning finished";
            // Could refresh available networks list in UI
            break;

        case NetworkEvent::kConnecting:
            // Attempting to connect to a network
            LOG(INFO) << "Connecting to network: " << data;
            // Could update status bar with connecting message
            break;

        case NetworkEvent::kConnected:
            // Successfully connected to a network
            LOG(INFO) << "Connected to network: " << data;
            // Update connection status, IP address, etc.
            is_connected_ = true;
            // Could update UI to show connected status
            break;

        case NetworkEvent::kDisconnected:
            // Disconnected from network
            LOG(INFO) << "Disconnected from network: " << data;
            is_connected_ = false;
            // Propagate disconnect event to application layer
            if (network_event_callback_) {
                network_event_callback_(NetworkEvent::kDisconnected, data);
            }
            // Could trigger HandleNetworkDisconnectedEvent() equivalent behavior
            return; // Early return to avoid double-callback

        case NetworkEvent::kConnectionFailed:
            // Failed to connect to network
            LOG(WARNING) << "Failed to connect to network: " << data;
            is_connected_ = false;
            // Could update UI to show connection failure
            break;

        case NetworkEvent::kConfigurationModeEntered:
            // Device entered configuration mode (AP mode)
            LOG(INFO) << "Entered configuration mode";
            // Could update UI to show config mode
            break;

        case NetworkEvent::kConfigurationModeExited:
            // Device exited configuration mode
            LOG(INFO) << "Exited configuration mode";
            // Could update UI to show normal operation mode
            break;

        case NetworkEvent::kError:
            // Network error occurred
            LOG(ERROR) << "Network error: " << data;
            // Could trigger error handling procedures
            break;

        default:
            LOG(WARNING) << "Unknown network event received: " << static_cast<int>(event);
            break;
    }

    // Propagate the network event to the registered callback
    // This allows higher layers (application/protocol) to handle the events
    if (network_event_callback_) {
        network_event_callback_(event, data);
    }
}

