    json += "\"board_type\":\"" + std::string(BOARD_TYPE) + "\",";
    json += "\"board_name\":\"" + std::string(BOARD_NAME) + "\",";

    // Get system information if available
    auto* system_info = SystemInfo::GetInstance();
    if (system_info) {
        std::string firmware_version = system_info->GetFirmwareVersion();
        std::string hardware_version = system_info->GetHardwareVersion();

        if (!firmware_version.empty()) {
            json += "\"firmware_version\":\"" + firmware_version + "\",";
        }

        if (!hardware_version.empty()) {
            json += "\"hardware_version\":\"" + hardware_version + "\",";
        }
    }

    // Get board-specific information
    auto* board = Board::GetInstance();
    if (board) {
        std::string serial_number = board->GetSerialNumber();
        std::string mac_address = board->GetMacAddress();

        if (!serial_number.empty()) {
            json += "\"serial_number\":\"" + serial_number + "\",";
        }

        if (!mac_address.empty()) {
            json += "\"mac_address\":\"" + mac_address + "\",";
        }
    }

    // Get WiFi information if available
    auto* wifi_manager = WifiManager::GetInstance();
