void WifiBoard::SetPowerSaveLevel(PowerSaveLevel level) {
    // Store the current power save level
    currentPowerSaveLevel = level;

    // Configure power management based on the selected level
    switch (level) {
        case PowerSaveLevel::LOW_POWER:
            // Configure for maximum power savings
            // Reduce CPU frequency to minimum operational level
            #ifdef CONFIG_PM_ENABLE
            {
                esp_pm_config_esp32_t pm_config = {
                    .max_freq_mhz = 80,  // Lower CPU frequency
                    .min_freq_mhz = 40,  // Minimum frequency
                    .light_sleep_enable = true  // Enable light sleep
                };
                esp_pm_configure(&pm_config);
            }
            #endif

            // Configure PowerSaveTimer for aggressive power saving
            if (powerSaveTimer) {
                powerSaveTimer->SetAggressiveMode(true);
                powerSaveTimer->SetTimeouts(5000, 30000); // Shorter timeouts
            }

            // Enable WiFi power save mode
            esp_wifi_set_ps(WIFI_PS_MAX_MODEM);

            // Reduce peripheral activity
            SetPeripheralPowerMode(PERIPHERAL_LOW_POWER);
            break;

        case PowerSaveLevel::BALANCED:
            // Configure for balanced performance and power consumption
            #ifdef CONFIG_PM_ENABLE
            {
                esp_pm_config_esp32_t pm_config = {
                    .max_freq_mhz = 160, // Medium CPU frequency
                    .min_freq_mhz = 80,  // Moderate minimum frequency
                    .light_sleep_enable = true  // Enable light sleep
                };
                esp_pm_configure(&pm_config);
            }
            #endif

            // Configure PowerSaveTimer for normal operation
            if (powerSaveTimer) {
                powerSaveTimer->SetAggressiveMode(false);
                powerSaveTimer->SetTimeouts(15000, 60000); // Moderate timeouts
            }

            // Enable moderate WiFi power save
            esp_wifi_set_ps(WIFI_PS_MIN_MODEM);

            // Normal peripheral activity
            SetPeripheralPowerMode(PERIPHERAL_NORMAL);
            break;

        case PowerSaveLevel::PERFORMANCE:
            // Configure for maximum performance
            #ifdef CONFIG_PM_ENABLE
            {
                esp_pm_config_esp32_t pm_config = {
                    .max_freq_mhz = 240, // Maximum CPU frequency
                    .min_freq_mhz = 160, // Higher minimum frequency
                    .light_sleep_enable = false // Disable light sleep for lowest latency
                };
                esp_pm_configure(&pm_config);
            }
            #endif

            // Configure PowerSaveTimer for performance mode
            if (powerSaveTimer) {
                powerSaveTimer->SetAggressiveMode(false);
                powerSaveTimer->SetTimeouts(30000, 120000); // Longer timeouts
            }

            // Disable WiFi power save for maximum performance
            esp_wifi_set_ps(WIFI_PS_NONE);

            // Full peripheral activity
            SetPeripheralPowerMode(PERIPHERAL_HIGH_PERFORMANCE);
            break;
    }

    // Notify other subsystems about the power save level change
    NotifyPowerSaveLevelChanged(level);

    // Wake up the power save timer to apply new settings
    if (powerSaveTimer) {
        powerSaveTimer->WakeUp();
    }
}

