This constructor must perform the following steps, as inferred from its relationship with `CircularStrip` and common patterns in ESP-IDF-based LED drivers:

---

#### Key Responsibilities of `SingleLed(gpio_num_t)`:

1. **Initialize LED Strip for One LED**
   - Use `led_strip_new_rmt_device()` to create a handle (`led_strip_handle_t`) for a WS2812-style LED.
   - Hardcode `max_leds = 1`, since this is a single LED controller.
   - Set color format to `LED_STRIP_COLOR_COMPONENT_FMT_GRB`.

2. **Initialize Internal State**
   - Set initial RGB values (`r_`, `g_`, `b_`) to zero (off).

3. **Create Blink Timer**
   - Use `esp_timer_create()` to set up a timer that will be used for blinking effects.
   - Assign it to member variable `blink_timer_`.
   - Provide a valid callback function (likely `OnBlinkTimer`) that can be invoked periodically.

4. **Mutex Initialization**
   - Protect concurrent access to shared resources like LED state or timers using a mutex.

5. **Error Handling**
   - Check return status from all ESP-IDF APIs and potentially log errors or assert if critical failures occur.

6. **Clear LEDs Initially**
   - Call `led_strip_clear()` after initialization to ensure the LED starts off.

---

With these points in mind, here's the full implementation of the constructor inside the required code block:

```cpp
#include "main/led/single_led.h"
#include <driver/rmt.h>
#include <led_strip.h>
#include <esp_timer.h>
#include <cstring> // For memset

SingleLed::SingleLed(gpio_num_t gpio_num) : r_(0), g_(0), b_(0), blink_timer_(nullptr) {
    // Configure LED strip configuration for one WS2812 LED
    led_strip_config_t strip_config = {};
    strip_config.strip_gpio_num = gpio_num;
    strip_config.max_leds = 1;
    strip_config.led_pixel_format = LED_PIXEL_FORMAT_GRB;
    strip_config.led_model = LED_MODEL_WS2812;
    strip_config.flags.invert_out = false;

    // Configure RMT-specific settings
    led_strip_rmt_config_t rmt_config = {};
    rmt_config.clk_src = RMT_CLK_SRC_DEFAULT;
    rmt_config.resolution_hz = 10 * 1000 * 1000; // 10MHz resolution
    rmt_config.mem_block_symbols = 64;             // Default value
    rmt_config.flags.with_dma = false;

    // Create LED strip instance
    esp_err_t err = led_strip_new_rmt_device(&strip_config, &rmt_config, &led_strip_);
    if (err != ESP_OK) {
        // Handle error appropriately, e.g., assert or log
        return;
    }

    // Clear any existing data on the strip
    led_strip_->clear(led_strip_, 50);

    // Mutex creation (assuming FreeRTOS-based environment)
    mutex_ = xSemaphoreCreateMutex();
    if (mutex_ == nullptr) {
        // Failed to create mutex
        return;
    }

    // Create blink timer
    esp_timer_create_args_t timer_args = {};
    timer_args.callback = &SingleLed::OnBlinkTimerCallback;
    timer_args.arg = this;
    timer_args.dispatch_method = ESP_TIMER_TASK;
    timer_args.name = "single_led_blink_timer";

    err = esp_timer_create(&timer_args, &blink_timer_);
    if (err != ESP_OK) {
        // Failed to create timer
        vSemaphoreDelete(mutex_);
        return;
    }
}

~SingleLed() {
    // Stop the blink timer first
    if (blink_timer_ != nullptr) {
        esp_timer_stop(blink_timer_);
        esp_timer_delete(blink_timer_);
        blink_timer_ = nullptr;
    }

    // Free the LED strip resource
    if (led_strip_ != nullptr) {
        led_strip_del(led_strip_);
        led_strip_ = nullptr;
    }

    // Clean up mutex if it exists
    if (mutex_ != nullptr) {
        vSemaphoreDelete(mutex_);
        mutex_ = nullptr;
    }
}

void SingleLed::SetColor(uint8_t r, uint8_t g, uint8_t b) {
    r_ = r;
    g_ = g;
    b_ = b;
}

void TurnOn() {
    std::lock_guard<std::mutex> lock(mutex_);

    // Stop any active blink timer to prevent conflicts
    if (blink_timer_ != nullptr) {
        esp_timer_stop(blink_timer_);
    }

    // Set all pixels to current color values
    for (int i = 0; i < led_count_; i++) {
        led_strip_set_pixel(led_strip_, i, r_, g_, b_);
    }

    // Refresh the LED strip to apply changes
    led_strip_refresh(led_strip_);
}

void CircularStrip::TurnOff() {
    // Lock mutex for thread safety
    std::lock_guard<std::mutex> lock(strip_mutex_);

    // Stop any ongoing timer tasks
    if (strip_timer_) {
        esp_timer_stop(strip_timer_);
    }

    // Clear all LEDs immediately
    led_strip_clear();

    // Optionally, we could also set internal state variables
    // to indicate the strip is off, depending on class design
}

void StartBlinkTask(int times, int interval_ms) {
    std::lock_guard<std::mutex> lock(mutex_);

    // Stop any currently active blink timer
    esp_timer_stop(blink_timer_handle_);

    // Update blink parameters
    if (times == BLINK_INFINITE) {
        blink_counter_ = BLINK_INFINITE;
    } else {
        blink_counter_ = times * 2;  // Each blink has two transitions: on/off
    }

    blink_interval_ms_ = interval_ms;

    // Start the periodic timer with interval in microseconds
    esp_timer_start_periodic(blink_timer_handle_, static_cast<uint64_t>(interval_ms) * 1000ULL);
}

void SingleLed::OnBlinkTimer() {
    std::lock_guard<std::mutex> lock(mutex_);

    if (blink_counter_ > 0) {
        // Decrement the blink counter
        blink_counter_--;

        // Toggle LED state based on whether the counter is even or odd
        if (blink_counter_ % 2 == 0) {
            // Turn LED on - set pixel to the stored color
            led_strip_set_pixel(led_strip_, 0, r_, g_, b_);
        } else {
            // Turn LED off - clear the strip
            led_strip_clear(led_strip_);
        }

        // Refresh the LED strip to apply changes
        led_strip_refresh(led_strip_);
    }

    // If we've completed all blink cycles, stop the timer
    if (blink_counter_ == 0) {
        esp_timer_stop(blink_timer_);
    }
}

void SingleLed::OnStateChanged() {
    // Retrieve the current device state from the application instance
    DeviceState state = Application::GetInstance().GetDeviceState();

    // Lock the mutex to ensure thread-safe access to LED operations
    std::lock_guard<std::mutex> lock(mutex_);

    switch (state) {
        case kDeviceStateStarting:
            SetColor(0xFFA500); // Orange color
            TurnOn();
            break;

        case kDeviceStateIdle:
            TurnOff();
            break;

        case kDeviceStateListening:
            SetColor(0x00FF00); // Green color
            TurnOn();
            break;

        case kDeviceStateSpeaking:
            SetColor(0x0000FF); // Blue color
            TurnOn();
            break;

        case kDeviceStateUpgrading:
            StartBlinkTask(200); // Fast blink: 200ms on/off
            break;

        case kDeviceStateActivating:
            StartBlinkTask(1000); // Slow blink: 1s on/off
            break;

        default:
            TurnOff(); // Safe fallback: turn off LED
            break;
    }
}

