bool MqttProtocol::StartMqttClient(bool report_error) {
    // Check if MQTT client is already running
    if (mqtt_client_ != nullptr) {
        // If client exists, clean it up before creating a new one
        CleanupMqttClient();
    }

    // Create new MQTT client instance
    mqtt_client_ = mqtt_client_new();
    if (mqtt_client_ == nullptr) {
        if (report_error) {
            // Report error to application layer
            NotifyApplicationError("Failed to create MQTT client");
        }
        return false;
    }

    // Configure MQTT client settings
    mqtt_client_config_t config = {0};
    config.broker_url = broker_url_.c_str();
    config.username = username_.c_str();
    config.password = password_.c_str();
    config.client_id = client_id_.c_str();

    // Set certificates if TLS is enabled
    if (use_tls_) {
        config.ca_cert = ca_cert_.c_str();
        config.client_cert = client_cert_.c_str();
        config.client_key = client_key_.c_str();
    }

    // Apply configuration to MQTT client
    if (mqtt_client_set_config(mqtt_client_, &config) != MQTT_SUCCESS) {
        if (report_error) {
            NotifyApplicationError("Failed to configure MQTT client");
        }
        CleanupMqttClient();
        return false;
    }

    // Set up event callbacks
    mqtt_client_set_event_callback(mqtt_client_, MqttEventHandler, this);

    // Attempt to connect to MQTT broker
    mqtt_error_t connect_result = mqtt_client_connect(mqtt_client_);
    if (connect_result != MQTT_SUCCESS) {
        if (report_error) {
            std::string error_msg = "MQTT connection failed: " + std::to_string(connect_result);
            NotifyApplicationError(error_msg.c_str());
        }
        CleanupMqttClient();
        return false;
    }

    // Connection successful
    is_connected_ = true;

    // Reset reconnection attempt counter on successful connection
    reconnection_attempts_ = 0;

    // Stop reconnection timer since we're now connected
    if (reconnect_timer_ != nullptr) {
        timer_stop(reconnect_timer_);
    }

    // Initialize any pending subscriptions
    InitializeSubscriptions();

    return true;
}

bool MqttProtocol::SendText(const std::string& text) {
    if (mqtt_ == nullptr || !mqtt_->IsConnected()) {
        ESP_LOGE(TAG, "MQTT is not connected");
        SetError("MQTT not connected");
        return false;
    }

    if (publish_topic_.empty()) {
        ESP_LOGE(TAG, "Publish topic is not set");
        SetError("Publish topic not configured");
        return false;
    }

    ESP_LOGI(TAG, "Sending text message to topic '%s': %s", publish_topic_.c_str(), text.c_str());

    bool result = mqtt_->Publish(publish_topic_, text);
    if (!result) {
        ESP_LOGE(TAG, "Failed to publish message to topic '%s'", publish_topic_.c_str());
        SetError("Failed to publish MQTT message");
    }

    return result;
}

bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    // Check if the UDP audio channel is open before proceeding
    if (!IsAudioChannelOpened()) {
        return false;
    }

    // Validate input packet
    if (!packet || packet->data.empty()) {
        return false;
    }

    // Prepare header fields
    uint8_t type = static_cast<uint8_t>(packet->type);
    uint8_t flags = packet->flags;
    uint16_t ssrc = packet->ssrc;
    uint32_t timestamp = packet->timestamp;
    uint16_t sequence = local_sequence_.fetch_add(1);

    // Serialize packet: [Type(1)][Flags(1)][Length(2)][SSRC(2)][Timestamp(4)][Sequence(2)][Data(N)]
    std::vector<uint8_t> buffer;
    size_t header_size = sizeof(type) + sizeof(flags) + sizeof(uint16_t) + sizeof(ssrc) +
                         sizeof(timestamp) + sizeof(sequence);
    size_t total_size = header_size + packet->data.size();

    buffer.resize(total_size);

    size_t offset = 0;

    // Write fixed-size header fields
    std::memcpy(buffer.data() + offset, &type, sizeof(type));
    offset += sizeof(type);

    std::memcpy(buffer.data() + offset, &flags, sizeof(flags));
    offset += sizeof(flags);

    uint16_t net_len = htons(static_cast<uint16_t>(packet->data.size()));
    std::memcpy(buffer.data() + offset, &net_len, sizeof(net_len));
    offset += sizeof(net_len);

    uint16_t net_ssrc = htons(ssrc);
    std::memcpy(buffer.data() + offset, &net_ssrc, sizeof(net_ssrc));
    offset += sizeof(net_ssrc);

    uint32_t net_timestamp = htonl(timestamp);
    std::memcpy(buffer.data() + offset, &net_timestamp, sizeof(net_timestamp));
    offset += sizeof(net_timestamp);

    uint16_t net_sequence = htons(sequence);
    std::memcpy(buffer.data() + offset, &net_sequence, sizeof(net_sequence));
    offset += sizeof(net_sequence);

    // Copy payload data
    std::memcpy(buffer.data() + offset, packet->data.data(), packet->data.size());

    // Encrypt the full buffer using AES-CTR mode
    std::vector<uint8_t> encrypted_buffer(buffer.size());
    if (!EncryptAesCtr(buffer.data(), buffer.size(), encrypted_buffer.data())) {
        return false; // Encryption failed
    }

    // Send the encrypted packet via UDP
    if (!udp_->Send(encrypted_buffer.data(), encrypted_buffer.size())) {
        return false; // Failed to send over UDP
    }

    return true;
}

void MqttProtocol::CloseAudioChannel() {
    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Reset the UDP connection to release resources
    udp_.reset();

    // Notify upper layers if callback is registered
    if (on_audio_channel_closed_) {
        on_audio_channel_closed_();
    }
}

int MqttProtocol::OpenAudioChannel() {
    // Step 0: Lock the channel mutex for safe access to 'udp_' member
    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Prevent re-initialization if already open
    if (udp_ != nullptr) {
        return -1; // Already open
    }

    // Step 1: Send "hello" message via MQTT to prompt server response with UDP config
    // Assuming GetHelloMessage() constructs and sends the correct payload
    int result = SendMqttMessage(GetHelloMessage());
    if (result != 0) {
        return result;
    }

    // Wait for server hello (containing UDP config)
    // This assumes there's a mechanism to wait/poll until server_hello_json_ is populated
    // For simplicity, let's say we now have valid server_hello_json_

    const cJSON *server_hello_json = GetLastReceivedServerHello(); // placeholder method
    if (!server_hello_json) {
        return -2; // No server hello received
    }

    // Step 2: Validate Transport Type ("udp")
    const cJSON *transport_item = cJSON_GetObjectItemCaseSensitive(server_hello_json, "transport");
    if (!cJSON_IsString(transport_item) || strcmp(transport_item->valuestring, "udp") != 0) {
        return -3; // Invalid or unsupported transport type
    }

    // Step 3: Extract UDP Config Parameters
    const cJSON *udp_config = cJSON_GetObjectItemCaseSensitive(server_hello_json, "udp");
    if (!cJSON_IsObject(udp_config)) {
        return -4; // Missing UDP config section
    }

    const cJSON *server_item = cJSON_GetObjectItemCaseSensitive(udp_config, "server");
    const cJSON *port_item = cJSON_GetObjectItemCaseSensitive(udp_config, "port");
    const cJSON *key_item = cJSON_GetObjectItemCaseSensitive(udp_config, "key");
    const cJSON *nonce_item = cJSON_GetObjectItemCaseSensitive(udp_config, "nonce");

    if (!cJSON_IsString(server_item) || !cJSON_IsNumber(port_item) ||
        !cJSON_IsString(key_item) || !cJSON_IsString(nonce_item)) {
        return -5; // Missing or invalid UDP parameters
    }

    std::string server = server_item->valuestring;
    uint16_t port = static_cast<uint16_t>(port_item->valuedouble);
    std::string key_hex = key_item->valuestring;
    std::string nonce_hex = nonce_item->valuestring;

    // Convert hex strings to binary buffers
    std::vector<uint8_t> key = HexStringToBytes(key_hex);
    std::vector<uint8_t> nonce = HexStringToBytes(nonce_hex);

    if (key.size() != 16 || nonce.size() != 12) { // Example sizes for AES-128-GCM
        return -6; // Invalid key or nonce size
    }

    // Step 4: Initialize AES Decryption Context using mbedTLS
    mbedtls_gcm_init(&aes_ctx_);
    int ret = mbedtls_gcm_setkey(&aes_ctx_, MBEDTLS_CIPHER_ID_AES, key.data(), key.size() * 8);
    if (ret != 0) {
        mbedtls_gcm_free(&aes_ctx_);
        return -7; // Failed to set AES key
    }

    // Store nonce for later use during decryption
    memcpy(aes_nonce_, nonce.data(), sizeof(aes_nonce_));

    // Step 5: Create UdpCommunicationHandler Instance
    auto* network_interface = Board::GetInstance().GetNetwork();
    if (!network_interface) {
        mbedtls_gcm_free(&aes_ctx_);
        return -8; // Network interface unavailable
    }

    udp_ = std::make_unique<UdpCommunicationHandler>(network_interface);
    if (!udp_) {
        mbedtls_gcm_free(&aes_ctx_);
        return -9; // Memory allocation failed
    }

    // Connect to remote endpoint
    int connect_result = udp_->Connect(server.c_str(), port);
    if (connect_result != 0) {
        udp_.reset();
        mbedtls_gcm_free(&aes_ctx_);
        return -10; // Connection failed
    }

    return 0; // Success
}

std::string GetHelloMessage() {
    // Create the root JSON object
    cJSON *root = cJSON_CreateObject();

    // Add basic fields
    cJSON_AddStringToObject(root, "type", "hello");
    cJSON_AddNumberToObject(root, "version", 1);
    cJSON_AddStringToObject(root, "transport", "udp");

    // Create audio_params object
    cJSON *audio_params = cJSON_CreateObject();
    cJSON_AddStringToObject(audio_params, "format", "opus");
    cJSON_AddNumberToObject(audio_params, "sample_rate", 16000);
    cJSON_AddNumberToObject(audio_params, "channels", 1);
    cJSON_AddNumberToObject(audio_params, "frame_duration", 60);

    // Add audio_params to root
    cJSON_AddItemToObject(root, "audio_params", audio_params);

    // Convert to string
    char *json_string = cJSON_PrintUnformatted(root);
    std::string result(json_string ? json_string : "");

    // Clean up
    if (json_string) {
        cJSON_free(json_string);
    }
    cJSON_Delete(root);

    return result;
}

bool MqttProtocol::ParseServerHello(const cJSON* json_root) {
    // Validate that transport type is "udp"
    if (!ValidateTransport(json_root)) {
        ESP_LOGE(TAG, "Invalid transport type");
        return false;
    }

    // Extract and validate UDP configuration
    if (!ValidateAndExtractUdpConfig(json_root)) {
        ESP_LOGE(TAG, "Failed to extract UDP configuration");
        return false;
    }

    // Initialize sequence numbers and signal event
    InitializeSequenceAndEvent();

    return true;
}

bool MqttProtocol::ValidateTransport(const cJSON* json_root) {
    cJSON* transport_obj = cJSON_GetObjectItemCaseSensitive(json_root, "transport");
    if (transport_obj == nullptr || !cJSON_IsString(transport_obj)) {
        return false;
    }

    std::string transport_type = transport_obj->valuestring;
    return transport_type == "udp";
}

bool MqttProtocol::ValidateAndExtractUdpConfig(const cJSON* json_root) {
    cJSON* udp_obj = cJSON_GetObjectItemCaseSensitive(json_root, "udp");
    if (udp_obj == nullptr || !cJSON_IsObject(udp_obj)) {
        return false;
    }

    // Extract server
    cJSON* server_obj = cJSON_GetObjectItemCaseSensitive(udp_obj, "server");
    if (server_obj == nullptr || !cJSON_IsString(server_obj)) {
        return false;
    }
    server_address_ = server_obj->valuestring;

    // Extract port
    cJSON* port_obj = cJSON_GetObjectItemCaseSensitive(udp_obj, "port");
    if (port_obj == nullptr || !cJSON_IsNumber(port_obj)) {
        return false;
    }
    server_port_ = port_obj->valueint;

    // Extract key
    cJSON* key_obj = cJSON_GetObjectItemCaseSensitive(udp_obj, "key");
    if (key_obj == nullptr || !cJSON_IsString(key_obj)) {
        return false;
    }
    std::vector<uint8_t> key_data = DecodeHexString(key_obj->valuestring);
    if (key_data.empty() || key_data.size() != 16) { // 128-bit key
        return false;
    }

    // Extract nonce
    cJSON* nonce_obj = cJSON_GetObjectItemCaseSensitive(udp_obj, "nonce");
    if (nonce_obj == nullptr || !cJSON_IsString(nonce_obj)) {
        return false;
    }
    std::vector<uint8_t> nonce_data = DecodeHexString(nonce_obj->valuestring);
    if (nonce_data.empty() || nonce_data.size() != 16) { // 128-bit nonce
        return false;
    }

    // Copy key and nonce data
    memcpy(aes_key_, key_data.data(), 16);
    memcpy(nonce_, nonce_data.data(), 16);

    // Initialize AES context
    mbedtls_aes_init(&aes_ctx_);
    int ret = mbedtls_aes_setkey_enc(&aes_ctx_, aes_key_, 128);
    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to set AES key: %d", ret);
        return false;
    }

    return true;
}

void MqttProtocol::InitializeSequenceAndEvent() {
    // Initialize sequence numbers
    local_sequence_ = 0;
    remote_sequence_ = 0;

    // Signal that ServerHello has been processed
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
}

static inline unsigned char CharToHex(char c) {
    if (c >= '0' && c <= '9') {
        return c - '0';
    } else if (c >= 'A' && c <= 'F') {
        return c - 'A' + 10;
    } else if (c >= 'a' && c <= 'f') {
        return c - 'a' + 10;
    }
    // Return 0 for invalid characters or handle error as needed
    return 0;
}

std::string DecodeHexString(const std::string &hexString) {
    // Reserve memory for efficiency - output will be half the input size
    std::string result;
    result.reserve(hexString.length() / 2);

    // Process pairs of hexadecimal characters
    for (size_t i = 0; i < hexString.length(); i += 2) {
        // Convert each hex character to its numeric value
        char highNibble = CharToHex(hexString[i]);
        char lowNibble = CharToHex(hexString[i + 1]);

        // Combine the two nibbles into a single byte
        char byte = (highNibble << 4) | lowNibble;

        // Add the decoded byte to the result
        result.push_back(byte);
    }

    return result;
}

