    SendText(message);
}

// Helper function to escape JSON special characters in the payload
std::string EscapeJsonString(const std::string& input) {
    std::string result;
    result.reserve(input.length());

    for (char c : input) {
        switch (c) {
            case '\"': result += "\\\""; break;
            case '\\': result += "\\\\"; break;
            case '\b': result += "\\b"; break;
            case '\f': result += "\\f"; break;
            case '\n': result += "\\n"; break;
            case '\r': result += "\\r"; break;
            case '\t': result += "\\t"; break;
            default:
                if (c < 0x20) {
                    // Convert control characters to \u00XX format
                    char hex[7];
                    snprintf(hex, sizeof(hex), "\\u%04x", c);
                    result += hex;
                } else {
                    result += c;
                }
                break;
        }
    }

    return result;
}

