bool AudioService::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    // Check if WebSocket is connected
    if (!websocket_ || !websocket_->IsConnected()) {
        return false;
    }

    // Handle null packet
    if (!packet) {
        return false;
    }

    switch (version_) {
        case 2: {
            // BinaryProtocol2: version(4) + timestamp(8) + payload_size(4) + payload(payload_size)
            uint32_t version_net = htonl(version_);
            uint64_t timestamp_net = htobe64(packet->timestamp);
            uint32_t payload_size_net = htonl(static_cast<uint32_t>(packet->payload.size()));

            // Calculate total size
            size_t total_size = sizeof(version_net) + sizeof(timestamp_net) + 
                               sizeof(payload_size_net) + packet->payload.size();

            // Create buffer for serialized data
            std::vector<uint8_t> buffer(total_size);
            size_t offset = 0;

            // Copy version
            memcpy(buffer.data() + offset, &version_net, sizeof(version_net));
            offset += sizeof(version_net);

            // Copy timestamp
            memcpy(buffer.data() + offset, &timestamp_net, sizeof(timestamp_net));
            offset += sizeof(timestamp_net);

            // Copy payload size
            memcpy(buffer.data() + offset, &payload_size_net, sizeof(payload_size_net));
            offset += sizeof(payload_size_net);

            // Copy payload
            if (!packet->payload.empty()) {
                memcpy(buffer.data() + offset, packet->payload.data(), packet->payload.size());
            }

            // Send through WebSocket
            return websocket_->SendBinary(buffer.data(), buffer.size());
        }

        case 3: {
            // BinaryProtocol3: simplified header - timestamp(8) + payload_size(4) + payload
            uint64_t timestamp_net = htobe64(packet->timestamp);
            uint32_t payload_size_net = htonl(static_cast<uint32_t>(packet->payload.size()));

            // Calculate total size
            size_t total_size = sizeof(timestamp_net) + sizeof(payload_size_net) + packet->payload.size();

            // Create buffer for serialized data
            std::vector<uint8_t> buffer(total_size);
            size_t offset = 0;

            // Copy timestamp
            memcpy(buffer.data() + offset, &timestamp_net, sizeof(timestamp_net));
            offset += sizeof(timestamp_net);

            // Copy payload size
            memcpy(buffer.data() + offset, &payload_size_net, sizeof(payload_size_net));
            offset += sizeof(payload_size_net);

            // Copy payload
            if (!packet->payload.empty()) {
                memcpy(buffer.data() + offset, packet->payload.data(), packet->payload.size());
            }

            // Send through WebSocket
            return websocket_->SendBinary(buffer.data(), buffer.size());
        }

        default: {
            // For other versions, send raw payload data directly
            if (!packet->payload.empty()) {
                return websocket_->SendBinary(packet->payload.data(), packet->payload.size());
            }
            return true; // Successfully sent empty packet
        }
    }
}

bool SendText(const std::string &text) {
    // Check if websocket is properly initialized and connected
    if (!websocket_) {
        ESP_LOGE("WS", "WebSocket not initialized");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    // Attempt to send the text through the websocket
    if (!websocket_->Send(text)) {
        ESP_LOGE("WS", "Failed to send text message");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    // Successfully sent the message
    return true;
}

bool WebsocketProtocol::OpenAudioChannel() {
    // Step 1: Fetch configuration from Settings
    std::string url = Settings::GetInstance()->GetString("audio_url");
    std::string token = Settings::GetInstance()->GetString("auth_token");
    std::string version = Settings::GetInstance()->GetString("protocol_version");

    if (url.empty() || token.empty()) {
        SetError(Lang::Strings::Get(Lang::kInvalidConfiguration));
        return false;
    }

    // Ensure token starts with 'Bearer '
    if (token.find("Bearer ") != 0) {
        token = "Bearer " + token;
    }

    // Step 2: Initialize WebSocket Client
    auto network_interface = Board::GetInstance().GetNetwork();
    websocket_client_ = network_interface->CreateWebSocketClient(url);
    if (!websocket_client_) {
        SetError(Lang::Strings::Get(Lang::kFailedToCreateWebSocket));
        return false;
    }

    // Step 3: Prepare Headers
    std::map<std::string, std::string> headers;
    headers["Authorization"] = token;
    headers["X-Protocol-Version"] = version;
    headers["X-Mac-Address"] = SystemInfo::GetMacAddress();
    headers["X-Device-ID"] = Board::GetInstance().GetUuid();

    // Apply headers to WebSocket client
    for (const auto& pair : headers) {
        websocket_client_->SetHeader(pair.first, pair.second);
    }

    // Step 4: Register callbacks
    websocket_client_->SetOnDataCallback([this](const uint8_t* data, size_t len) {
        OnData(data, len);
    });
    websocket_client_->SetOnDisconnectedCallback([this]() {
        OnDisconnected();
    });

    // Step 5: Connect
    if (!websocket_client_->Connect()) {
        SetError(Lang::Strings::Get(Lang::kConnectionFailed));
        return false;
    }

    // Step 6: Send Hello Message
    std::string hello_msg = GetHelloMessage();
    if (!websocket_client_->SendText(hello_msg)) {
        SetError(Lang::Strings::Get(Lang::kSendMessageFailed));
        return false;
    }

    // Step 7: Wait for Server Response
    EventBits_t bits = xEventGroupWaitBits(
        event_group_,
        WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,   // Clear on exit
        pdFALSE,  // Wait for any bit
        pdMS_TO_TICKS(10000)); // Timeout after 10 seconds

    if (!(bits & WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT)) {
        SetError(Lang::Strings::Get(Lang::kServerHelloTimeout));
        return false;
    }

    // Step 8: Notify Success
    if (on_audio_channel_opened_) {
        on_audio_channel_opened_();
    }

    return true;
}

std::string GetHelloMessage() {
    cJSON *root = cJSON_CreateObject();
    if (!root) {
        return "";
    }

    // Add basic fields
    cJSON_AddStringToObject(root, "type", "hello");
    cJSON_AddNumberToObject(root, "version", version_);
    cJSON_AddStringToObject(root, "transport", "websocket");

    // Add features object
    cJSON *features = cJSON_CreateObject();
    if (!features) {
        cJSON_Delete(root);
        return "";
    }
    cJSON_AddBoolToObject(features, "mcp", true);

#ifdef CONFIG_USE_SERVER_AEC
    cJSON_AddBoolToObject(features, "aec", true);
#endif

    cJSON_AddItemToObject(root, "features", features);

    // Add audio parameters
    cJSON *audio_params = cJSON_CreateObject();
    if (!audio_params) {
        cJSON_Delete(root);
        return "";
    }

    cJSON_AddStringToObject(audio_params, "encoding", "opus");
    cJSON_AddNumberToObject(audio_params, "sample_rate", 16000);
    cJSON_AddNumberToObject(audio_params, "channels", 1);
    cJSON_AddNumberToObject(audio_params, "frame_duration", OPUS_FRAME_DURATION_MS);

    cJSON_AddItemToObject(root, "audio_params", audio_params);

    // Serialize to string
    char *json_string = cJSON_PrintUnformatted(root);
    if (!json_string) {
        cJSON_Delete(root);
        return "";
    }

    std::string result(json_string);

    // Clean up
    cJSON_free(json_string);
    cJSON_Delete(root);

    return result;
}

bool WebsocketProtocol::ParseServerHello(const cJSON *json_obj) {
    // Check if json object is valid
    if (json_obj == nullptr) {
        return false;
    }

    // Check that the "transport" field exists and matches "websocket"
    cJSON *transport_obj = cJSON_GetObjectItem(json_obj, "transport");
    if (transport_obj == nullptr || !cJSON_IsString(transport_obj)) {
        return false;
    }

    const char *transport_str = cJSON_GetStringValue(transport_obj);
    if (transport_str == nullptr || strcmp(transport_str, "websocket") != 0) {
        return false;
    }

    // Extract optional "session_id" string for session tracking
    cJSON *session_id_obj = cJSON_GetObjectItem(json_obj, "session_id");
    if (session_id_obj != nullptr && cJSON_IsString(session_id_obj)) {
        const char *session_id_str = cJSON_GetStringValue(session_id_obj);
        if (session_id_str != nullptr) {
            session_id_ = session_id_str;
        }
    }

    // Parse the "audio_params" object to retrieve sample_rate and frame_duration
    cJSON *audio_params_obj = cJSON_GetObjectItem(json_obj, "audio_params");
    if (audio_params_obj != nullptr && cJSON_IsObject(audio_params_obj)) {
        // Get sample_rate
        cJSON *sample_rate_obj = cJSON_GetObjectItem(audio_params_obj, "sample_rate");
        if (sample_rate_obj != nullptr && cJSON_IsNumber(sample_rate_obj)) {
            server_sample_rate_ = static_cast<int>(sample_rate_obj->valuedouble);
        }

        // Get frame_duration
        cJSON *frame_duration_obj = cJSON_GetObjectItem(audio_params_obj, "frame_duration");
        if (frame_duration_obj != nullptr && cJSON_IsNumber(frame_duration_obj)) {
            server_frame_duration_ = static_cast<int>(frame_duration_obj->valuedouble);
        }
    }

    // After successful parsing, call xEventGroupSetBits to signal completion
    if (event_group_handle_ != nullptr) {
        xEventGroupSetBits(event_group_handle_, WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT);
    }

    return true;
}
